import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import { Menu, X, LogOut, Sun, Moon } from 'lucide-react';

export default function Navbar() {
  const location = useLocation();
  const navigate = useNavigate();
  const [user, setUser] = useState(null);
  const [menuOpen, setMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [darkMode, setDarkMode] = useState(() => document.documentElement.getAttribute('data-theme') === 'dark');

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user ?? null);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null);
    });
    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 10);
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  useEffect(() => {
    setMenuOpen(false);
  }, [location.pathname]);

  const toggleDark = () => {
    const next = !darkMode;
    setDarkMode(next);
    document.documentElement.setAttribute('data-theme', next ? 'dark' : 'light');
    localStorage.setItem('theme', next ? 'dark' : 'light');
  };

  useEffect(() => {
    const saved = localStorage.getItem('theme');
    if (saved) {
      document.documentElement.setAttribute('data-theme', saved);
      setDarkMode(saved === 'dark');
    }
  }, []);

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setMenuOpen(false);
    navigate('/');
  };

  const isActive = (path) => location.pathname === path;
  const isAppPage = location.pathname === '/app';

  const navLinks = [
    { to: '/', label: 'Home' },
    { to: '/app', label: 'Console' },
    { to: '/tools', label: 'Tools' },
    { to: '/hosting', label: 'Hosting' },
    { to: '/pricing', label: 'Pricing' },
    { to: '/api-docs', label: 'API' },
  ];

  if (isAppPage) return null;

  return (
    <>
      <nav className="glass" style={{
        display: 'flex', justifyContent: 'space-between', alignItems: 'center',
        padding: '12px 5%',
        borderBottom: scrolled ? '1px solid var(--gray-border)' : '1px solid transparent',
        position: 'sticky', top: 0, zIndex: 1000,
        transition: 'border-color 0.3s, box-shadow 0.3s',
        boxShadow: scrolled ? 'var(--shadow-sm)' : 'none',
      }}>
        <Link to="/" style={{ fontSize: '20px', fontWeight: 900, letterSpacing: '-1px', color: 'var(--text-main)', textDecoration: 'none', transition: 'color 0.3s' }}>
          CEXISTORE<span style={{ color: 'var(--primary)' }}>.</span>
        </Link>

        {/* Desktop Nav */}
        <div style={{ display: 'flex', gap: '24px', alignItems: 'center' }} className="nav-desktop">
          {navLinks.map(link => (
            <Link key={link.to} to={link.to} style={{
              fontSize: '13px', fontWeight: 600,
              color: isActive(link.to) ? 'var(--primary)' : 'var(--text-sub)',
              textDecoration: 'none', transition: 'color 0.2s',
              position: 'relative',
              paddingBottom: '2px',
            }}>
              {link.label}
              {isActive(link.to) && (
                <span style={{ position: 'absolute', bottom: '-4px', left: '50%', transform: 'translateX(-50%)', width: '4px', height: '4px', background: 'var(--primary)', borderRadius: '50%' }} />
              )}
            </Link>
          ))}

          <button onClick={toggleDark} style={{
            background: 'none', border: 'none', cursor: 'pointer',
            color: 'var(--text-muted)', padding: '6px', display: 'flex',
            transition: 'color 0.2s'
          }} title="Toggle theme">
            {darkMode ? <Sun size={16} /> : <Moon size={16} />}
          </button>

          {user ? (
            <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
              <Link to="/app" className="btn-gh btn-blue" style={{
                fontSize: '12px', padding: '8px 18px', textDecoration: 'none'
              }}>Dashboard</Link>
              <button onClick={handleLogout} style={{
                background: 'none', border: 'none', cursor: 'pointer',
                color: 'var(--text-muted)', padding: '6px', display: 'flex'
              }} title="Logout">
                <LogOut size={16} />
              </button>
            </div>
          ) : (
            <Link to="/auth" className="btn-gh" style={{
              fontSize: '12px', fontWeight: 700, color: 'var(--white)',
              backgroundColor: 'var(--black)', padding: '8px 18px',
              borderColor: 'var(--black)', textDecoration: 'none'
            }}>Sign In</Link>
          )}
        </div>

        {/* Mobile */}
        <div style={{ display: 'none', alignItems: 'center', gap: '8px' }} className="nav-hamburger">
          <button onClick={toggleDark} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-muted)', padding: '4px', display: 'flex' }}>
            {darkMode ? <Sun size={18} /> : <Moon size={18} />}
          </button>
          <button onClick={() => setMenuOpen(!menuOpen)} style={{ background: 'none', border: 'none', cursor: 'pointer', padding: '4px', color: 'var(--text-main)', display: 'flex' }}>
            {menuOpen ? <X size={22} /> : <Menu size={22} />}
          </button>
        </div>
      </nav>

      {/* Mobile Menu */}
      {menuOpen && (
        <div style={{
          position: 'fixed', inset: 0, top: '52px',
          background: 'var(--white)',
          zIndex: 999, padding: '24px',
          display: 'flex', flexDirection: 'column', gap: '4px',
          animation: 'fadeIn 0.2s ease-out',
          transition: 'background 0.3s'
        }}>
          {navLinks.map(link => (
            <Link key={link.to} to={link.to} onClick={() => setMenuOpen(false)} style={{
              fontSize: '16px', fontWeight: 700, padding: '14px 0',
              color: isActive(link.to) ? 'var(--primary)' : 'var(--text-main)',
              textDecoration: 'none', borderBottom: '1px solid var(--gray-border)',
              transition: 'color 0.2s'
            }}>
              {link.label}
            </Link>
          ))}
          {user ? (
            <>
              <Link to="/app" onClick={() => setMenuOpen(false)} style={{
                fontSize: '16px', fontWeight: 700, padding: '14px 0',
                color: 'var(--primary)', textDecoration: 'none',
                borderBottom: '1px solid var(--gray-border)'
              }}>Dashboard</Link>
              <button onClick={handleLogout} style={{
                fontSize: '16px', fontWeight: 700, padding: '14px 0',
                color: 'var(--danger)', background: 'none', border: 'none',
                cursor: 'pointer', textAlign: 'left'
              }}>Logout</button>
            </>
          ) : (
            <Link to="/auth" onClick={() => setMenuOpen(false)} style={{
              fontSize: '16px', fontWeight: 700, padding: '14px 0',
              color: 'var(--text-main)', textDecoration: 'none'
            }}>Sign In</Link>
          )}
        </div>
      )}

      <style>{`
        @media (max-width: 640px) {
          .nav-desktop { display: none !important; }
          .nav-hamburger { display: flex !important; }
        }
      `}</style>
    </>
  );
}

import React, { createContext, useContext, useState, useCallback, useMemo, useRef } from 'react';

const ToastContext = createContext(null);

let toastId = 0;

export function ToastProvider({ children }) {
  const [toasts, setToasts] = useState([]);
  const timers = useRef({});

  const removeToast = useCallback((id) => {
    setToasts(prev => prev.filter(t => t.id !== id));
    if (timers.current[id]) {
      clearTimeout(timers.current[id]);
      delete timers.current[id];
    }
  }, []);

  const addToast = useCallback((message, type = 'info', duration = 3000) => {
    const id = ++toastId;
    setToasts(prev => [...prev.slice(-2), { id, message, type }]);
    timers.current[id] = setTimeout(() => removeToast(id), duration);
    return id;
  }, [removeToast]);

  const toast = useMemo(() => ({
    success: (msg) => addToast(msg, 'success'),
    error: (msg) => addToast(msg, 'error'),
    info: (msg) => addToast(msg, 'info'),
  }), [addToast]);

  return (
    <ToastContext.Provider value={toast}>
      {children}
      <div className="toast-container">
        {toasts.map(t => (
          <div key={t.id} className={`toast toast-${t.type}`} onClick={() => removeToast(t.id)}>
            <span>{t.type === 'success' ? '✓' : t.type === 'error' ? '✕' : 'ℹ'}</span>
            <span>{t.message}</span>
          </div>
        ))}
      </div>
    </ToastContext.Provider>
  );
}

export function useToast() {
  const ctx = useContext(ToastContext);
  if (!ctx) throw new Error('useToast must be inside ToastProvider');
  return ctx;
}

import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import { useToast } from '../components/Toast';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Shield, Users, Package, DollarSign, TrendingUp, CheckCircle, XCircle,
  Search, BarChart3, Activity, Crown, Mail, Zap, Clock, Edit3, Save, Lock,
  Globe, Server, Settings, Plus, Trash2, RefreshCw, Eye, Database, HardDrive, Box, Cloud, File, Download
} from 'lucide-react';
import { AreaChart, Area, PieChart, Pie, Cell, ResponsiveContainer, XAxis, YAxis, Tooltip, CartesianGrid } from 'recharts';

const WEB_API = window.location.origin + '/api/web';
const COLORS = ['#0066ff', '#0ea5e9', '#10b981', '#f59e0b', '#ef4444'];

export default function AdminPage() {
  const navigate = useNavigate();
  const toast = useToast();
  const [user, setUser] = useState(null);
  const [isAdmin, setIsAdmin] = useState(false);
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState('overview');
  const [stats, setStats] = useState(null);
  const [orders, setOrders] = useState([]);
  const [users, setUsers] = useState([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [editingUser, setEditingUser] = useState(null);
  const [editTokens, setEditTokens] = useState('');
  const [editPlan, setEditPlan] = useState('');

  const [domains, setDomains] = useState([]);
  const [newDomain, setNewDomain] = useState('');
  const [newDomainPremium, setNewDomainPremium] = useState(false);

  const [pteroOrders, setPteroOrders] = useState([]);
  const [inventory, setInventory] = useState([]);
  const [newInv, setNewInv] = useState({ platform: 'canva', email: '', password: '' });
  const [nodes, setNodes] = useState([]);
  const [newNode, setNewNode] = useState({ name: '', fqdn: '', memory: 2048, disk: 10240, plta_key: '' });
  const [eggs, setEggs] = useState([]);
  const [newEgg, setNewEgg] = useState({ name: '', description: '', egg_id: '', nest_id: '', color: '#0ea5e9' });

  const [sysConfig, setSysConfig] = useState({
    defaultTokens: 5, maxEmailTTL: 30, rateLimit: 10, maintenanceMode: false,
  });

  const [cloudFiles, setCloudFiles] = useState([]);
  const [driveAccounts, setDriveAccounts] = useState([]);
  const [newDrive, setNewDrive] = useState({ name: '', json: '' });

  const fetchAdmin = useCallback(async (userId) => {
    try {
      const [statsRes, ordersRes, usersRes, invRes, nodesRes, eggsRes, cloudRes, drivesRes] = await Promise.all([
        fetch(`${WEB_API}/admin/stats?adminId=${userId}`),
        fetch(`${WEB_API}/admin/orders?adminId=${userId}`),
        fetch(`${WEB_API}/admin/users?adminId=${userId}`),
        fetch(`${WEB_API}/admin/inventory?adminId=${userId}`),
        fetch(`${WEB_API}/admin/nodes?adminId=${userId}`),
        fetch(`${WEB_API}/admin/eggs?adminId=${userId}`),
        fetch(`${WEB_API}/admin/cloud?adminId=${userId}`),
        fetch(`${WEB_API}/admin/drives?adminId=${userId}`)
      ]);
      const [sj, oj, uj, ij, nj, ej, cj, dj] = await Promise.all([statsRes.json(), ordersRes.json(), usersRes.json(), invRes.json(), nodesRes.json(), eggsRes.json(), cloudRes.json(), drivesRes.json()]);
      if (sj.success) setStats(sj.stats);
      if (oj.success) setOrders(oj.orders || []);
      if (uj.success) setUsers(uj.users || []);
      if (ij.success) setInventory(ij.inventory || []);
      if (nj.success) setNodes(nj.nodes || []);
      if (ej.success) setEggs(ej.eggs || []);
      if (cj.success) setCloudFiles(cj.files || []);
      if (dj.success) setDriveAccounts(dj.drives || []);

      const domRes = await fetch(`${WEB_API}/profile?userId=${userId}`);
      const domJson = await domRes.json();
      if (domJson.domains) setDomains(domJson.domains);
    } catch (e) { console.error(e); }
  }, []);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (!session) { navigate('/auth'); return; }
      setUser(session.user);
      fetch(`${WEB_API}/profile?userId=${session.user.id}`)
        .then(r => r.json())
        .then(json => {
          if (json.profile?.is_admin) {
            setIsAdmin(true);
            fetchAdmin(session.user.id);
          }
          setLoading(false);
        });
    });
  }, [navigate, fetchAdmin]);

  const handleOrder = async (orderId, action) => {
    try {
      const res = await fetch(`${WEB_API}/admin/approve-order`, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ orderId, adminId: user.id, action }),
      });
      const json = await res.json();
      if (json.success) { toast.success(`Order ${action}d!`); fetchAdmin(user.id); }
      else toast.error(json.error);
    } catch { toast.error('Failed'); }
  };

  const handleUpdateUser = async (userId) => {
    try {
      const res = await fetch(`${WEB_API}/admin/update-user`, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ adminId: user.id, targetUserId: userId, tokens: parseInt(editTokens), plan: editPlan }),
      });
      const json = await res.json();
      if (json.success) { toast.success('User updated!'); setEditingUser(null); fetchAdmin(user.id); }
      else toast.error(json.error);
    } catch { toast.error('Failed'); }
  };

  const handleAddDomain = async () => {
    if (!newDomain.trim()) return;
    try {
      const { error } = await supabase.from('domains').insert({ domain: newDomain.trim(), is_active: true, is_premium: newDomainPremium });
      if (error) { toast.error(error.message); return; }
      toast.success('Domain added!');
      setNewDomain('');
      fetchAdmin(user.id);
    } catch { toast.error('Failed to add domain'); }
  };

  const handleToggleDomain = async (domainId, currentActive) => {
    const { error } = await supabase.from('domains').update({ is_active: !currentActive }).eq('id', domainId);
    if (!error) { toast.success('Domain updated!'); fetchAdmin(user.id); }
  };

  const handleDeleteDomain = async (domainId) => {
    const { error } = await supabase.from('domains').delete().eq('id', domainId);
    if (!error) { toast.success('Domain deleted!'); fetchAdmin(user.id); }
  };

  const handleAddInventory = async () => {
    if (!newInv.email || !newInv.password) return;
    const res = await fetch(`${WEB_API}/admin/inventory`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(newInv) });
    const json = await res.json();
    if (json.success) { toast.success('Account added!'); setNewInv({ platform: 'canva', email: '', password: '' }); fetchAdmin(user.id); }
    else toast.error(json.error);
  };

  const handleDeleteInventory = async (id) => {
    await fetch(`${WEB_API}/admin/inventory/${id}`, { method: 'DELETE' });
    toast.success('Deleted'); fetchAdmin(user.id);
  };

  const handleAddNode = async () => {
    if (!newNode.name || !newNode.fqdn || !newNode.plta_key) return;
    const res = await fetch(`${WEB_API}/admin/nodes`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(newNode) });
    const json = await res.json();
    if (json.success) { toast.success('Node added!'); setNewNode({ name: '', fqdn: '', memory: 2048, disk: 10240, plta_key: '' }); fetchAdmin(user.id); }
    else toast.error(json.error);
  };

  const handleDeleteNode = async (id) => {
    await fetch(`${WEB_API}/admin/nodes/${id}`, { method: 'DELETE' });
    toast.success('Node deleted'); fetchAdmin(user.id);
  };

  const handleAddEgg = async () => {
    if (!newEgg.name || !newEgg.egg_id || !newEgg.nest_id) return;
    const res = await fetch(`${WEB_API}/admin/eggs`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(newEgg) });
    const json = await res.json();
    if (json.success) { toast.success('Egg added!'); setNewEgg({ name: '', description: '', egg_id: '', nest_id: '', color: '#0ea5e9' }); fetchAdmin(user.id); }
    else toast.error(json.error);
  };

  const handleDeleteEgg = async (id) => {
    await fetch(`${WEB_API}/admin/eggs/${id}`, { method: 'DELETE' });
    toast.success('Egg deleted'); fetchAdmin(user.id);
  };

  const handleDeleteCloudFile = async (fileId) => {
    if (!confirm('Permanently delete this file from Google Drive?')) return;
    try {
      const res = await fetch(`${WEB_API}/admin/cloud/${fileId}`, {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ adminId: user.id }),
      });
      const json = await res.json();
      if (json.success) {
        toast.success('File deleted from cloud');
        fetchAdmin(user.id);
      } else {
        toast.error(json.error || 'Failed to delete');
      }
    } catch { toast.error('Network error'); }
  };

  const handleAddDrive = async () => {
    if (!newDrive.name.trim() || !newDrive.json.trim()) return;
    try {
      const res = await fetch(`${WEB_API}/admin/drives`, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: newDrive.name, credentialsJson: newDrive.json })
      });
      const json = await res.json();
      if (json.success) {
        toast.success('Drive Account added!');
        setNewDrive({ name: '', json: '' });
        fetchAdmin(user.id);
      } else toast.error(json.error || 'Invalid JSON format');
    } catch { toast.error('Network error'); }
  };

  const handleSetActiveDrive = async (id) => {
    try {
      const res = await fetch(`${WEB_API}/admin/drives/${id}/active`, { method: 'PUT' });
      const json = await res.json();
      if (json.success) { toast.success('Active drive updated!'); fetchAdmin(user.id); }
      else toast.error(json.error);
    } catch { toast.error('Network error'); }
  };

  const handleMigrateDrive = async (sourceId) => {
    const activeDrive = driveAccounts.find(d => d.is_active);
    if (!activeDrive) return toast.error('No active drive set for target!');
    if (activeDrive.id === sourceId) return toast.error('Source and target drive are the same!');

    if (!confirm(`WARNING: This will download all files from ${driveAccounts.find(d => d.id === sourceId)?.name} and upload them to ${activeDrive.name}. This may take a long time. Proceed?`)) return;

    try {
      const res = await fetch(`${WEB_API}/admin/cloud/migrate`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sourceDriveId: sourceId, targetDriveId: activeDrive.id })
      });
      const json = await res.json();
      if (json.success) {
        toast.success(json.message);
      } else {
        toast.error(json.error || 'Migration failed to start');
      }
    } catch { toast.error('Network error'); }
  };

  const handleDeleteDrive = async (id) => {
    if (!confirm('Remove this Drive account from the database? (Files previously uploaded will stay in the account)')) return;
    try {
      const res = await fetch(`${WEB_API}/admin/drives/${id}`, { method: 'DELETE' });
      const json = await res.json();
      if (json.success) { toast.success('Drive deleted'); fetchAdmin(user.id); }
      else toast.error('Failed to delete drive');
