                <div style={{ padding: '16px', borderRadius: 'var(--radius-md)', border: '1px solid var(--gray-border)', background: 'var(--white)' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
