                    <span style={{ fontSize: '12px', color: 'var(--text-muted)' }}>{c.date}</span>
                  </div>
                  {c.changes.map(ch => (
                    <div key={ch} style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '13px', color: 'var(--text-sub)', marginBottom: '4px' }}>
                      <CheckCircle size={12} style={{ color: '#10b981' }} /> {ch}
                    </div>
                  ))}
                </div>
              ))}
            </div>
          </Anim>
        </section>
      </div>
    </div>
  );
}

