  const fetchInbox = useCallback(async (addr) => {
    if (!addr) return;
    try {
      const res = await fetch(`${WEB_API}/inbox?email=${encodeURIComponent(addr)}`);
      const json = await res.json();
      if (json.success) setInbox(json.inbox);
    } catch (e) { console.error(e); }
  }, []);

  const handleProvision = async () => {
    if (isGenerating || !user || (profile?.tokens || 0) <= 0) {
      if ((profile?.tokens || 0) <= 0) toast.error('Insufficient tokens! Top up in Pricing.');
      return;
    }
    setIsGenerating(true);
    const name = customName.trim() || Math.random().toString(36).substring(2, 10);
    const addr = `${name}@${selectedDomain}`;

    try {
      const res = await fetch(`${WEB_API}/provision`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId: user.id, email: addr })
      });
      const json = await res.json();

      if (!json.success) {
        toast.error(json.error || 'Failed to provision');
        setIsGenerating(false);
        return;
      }

      if (json.profile) setProfile(json.profile);
      setCurrentEmail(addr);
      setEmailCreatedAt(Date.now());
      setInbox([]);
      setCustomName('');
      fetchAll(user);
      setGenerateSuccess(true);
      confetti();
      toast.success(`${addr} is now active!`);
      navigator.clipboard.writeText(addr);
      setTimeout(() => setGenerateSuccess(false), 2000);
    } catch (e) {
      toast.error('Network error: ' + e.message);
    }
    setIsGenerating(false);
  };

  const handleDeleteEmail = async (email) => {
    try {
      await fetch(`${WEB_API}/email`, {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId: user.id, email })
      });
      if (currentEmail === email) { setCurrentEmail(''); setInbox([]); }
      fetchAll(user);
      toast.info('Email removed');
    } catch { toast.error('Failed to delete'); }
  };

  const handleAttack = async () => {
    if (!stresserForm.target) { toast.error('Enter a target URL'); return; }
    setIsLaunching(true);
    try {
      await fetch(`${API_BASE}/attack-local`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(stresserForm)
      });
      toast.success('Signal dispatched!');
    } catch { toast.info('Signal sent'); }
    setIsLaunching(false);
  };

  const generateFake = useCallback(() => {
    const countries = [
      { name: 'Malaysia', code: '+60', prefix: '1', icPrefix: ['85','90','95','00','01'], states: ['Kuala Lumpur','Selangor','Johor','Penang','Sabah','Sarawak'], streets: ['Jalan Ampang','Jalan Bukit Bintang','Jalan Cheras','Jalan Damansara'] },
      { name: 'Indonesia', code: '+62', prefix: '8', icPrefix: ['32','33','34','35'], states: ['Jakarta','Bandung','Surabaya','Yogyakarta','Bali'], streets: ['Jl. Sudirman','Jl. Thamrin','Jl. Gatot Subroto'] },
      { name: 'Singapore', code: '+65', prefix: '9', icPrefix: ['S90','S95','T00','T05'], states: ['Central','East','West','North'], streets: ['Orchard Rd','Raffles Pl','Marina Bay'] },
      { name: 'Thailand', code: '+66', prefix: '8', icPrefix: ['1-1','1-2','2-1','3-1'], states: ['Bangkok','Chiang Mai','Phuket','Pattaya'], streets: ['Sukhumvit Rd','Silom Rd','Ratchada Rd'] },
    ];
    const c = countries[Math.floor(Math.random() * countries.length)];
    const first = ['Amir','Irfan','Sofea','Aisyah','Hafiz','Nurul','Danish','Syahmi','Farah','Aiman','Rizky','Dewi','Putri','Arief','Siti','Ahmad','Maya','Yuki'];
    const last = ['Rahman','Kassim','Ismail','Abdullah','Hassan','Zulkifli','Ahmad','Ibrahim','Prasetyo','Wijaya','Lim','Tan','Wong'];
    const genders = ['Male','Female'];
    const gender = genders[Math.floor(Math.random() * genders.length)];
    const year = 1985 + Math.floor(Math.random() * 25);
    const month = 1 + Math.floor(Math.random() * 12);
    const day = 1 + Math.floor(Math.random() * 28);
    setFakeIdentity({
      name: `${first[Math.floor(Math.random() * first.length)]} ${last[Math.floor(Math.random() * last.length)]}`,
      gender,
      dob: `${year}-${String(month).padStart(2,'0')}-${String(day).padStart(2,'0')}`,
      country: c.name,
      phone: `${c.code} ${c.prefix}${String(Math.floor(Math.random() * 100000000)).padStart(8, '0')}`,
      address: `No. ${Math.floor(Math.random() * 200) + 1}, ${c.streets[Math.floor(Math.random() * c.streets.length)]}, ${c.states[Math.floor(Math.random() * c.states.length)]}`,
      ic: `${c.icPrefix[Math.floor(Math.random() * c.icPrefix.length)]}${String(Math.floor(Math.random() * 10000)).padStart(4, '0')}-${String(Math.floor(Math.random() * 10000)).padStart(4, '0')}`,
      pass: `${Math.random().toString(36).slice(-8)}${Math.floor(Math.random() * 100)}!`,
    });
  }, []);

  const copyToClipboard = (text, field) => {
    navigator.clipboard.writeText(text);
    setCopiedField(field);
    toast.success('Copied!');
    setTimeout(() => setCopiedField(null), 2000);
  };

  const handleRefreshInbox = async () => {
    if (!currentEmail) return;
    setIsRefreshing(true);
    await fetchInbox(currentEmail);
    setIsRefreshing(false);
  };

  const handleDailyCheckin = async () => {
    if (!user) return;
    setDailyLoading(true);
    try {
      const res = await fetch(`${WEB_API}/daily-checkin`, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId: user.id }),
      });
      const json = await res.json();
      if (json.success) {
        toast.success(`Daily reward claimed! +${json.reward} token${json.reward > 1 ? 's' : ''}`);
        setProfile(json.profile);
        confetti();
      } else {
        toast.info(json.error || 'Already claimed today');
      }
    } catch { toast.error('Network error'); }
    setDailyLoading(false);
  };

  const handleApplyReferral = async () => {
    if (!user || !inputReferral.trim()) return;
    try {
      const res = await fetch(`${WEB_API}/apply-referral`, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId: user.id, referralCode: inputReferral.trim() }),
      });
      const json = await res.json();
      if (json.success) { toast.success(`Referral applied! +${json.bonus} tokens`); fetchAll(user); setInputReferral(''); }
      else toast.error(json.error);
    } catch { toast.error('Network error'); }
  };

  const fetchReferral = useCallback(async (uid) => {
    try {
      const res = await fetch(`${WEB_API}/referral-stats?userId=${uid}`);
      const json = await res.json();
      if (json.success) { setReferralCode(json.code); setReferralCount(json.count); }
    } catch {}
  }, []);

  const handleLogout = async () => {
    await supabase.auth.signOut();
    navigate('/auth');
  };

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (!session) return navigate('/auth');
      setUser(session.user);
      fetchAll(session.user).then(() => {
        generateFake();
        fetchReferral(session.user.id);
        setInitLoading(false);
      });
    });
