          transition={{ duration: 1, repeat: Infinity, ease: 'linear' }}
          style={{ width: '40px', height: '40px', border: '3px solid var(--gray-200)', borderTopColor: 'var(--primary)', borderRadius: '50%' }}
        />
        <motion.span
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.3 }}
          style={{ fontSize: '13px', fontWeight: 700, color: 'var(--text-muted)' }}
        >
          Loading Workspace...
        </motion.span>
      </div>
    );
  }

