                <div>
                  <div style={{ fontSize: '10px', fontWeight: 800, color: 'rgba(255,255,255,0.5)', letterSpacing: '1px', textTransform: 'uppercase', marginBottom: '6px' }}>Active Identity</div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                    <span className="live-dot" style={{ width: '8px', height: '8px' }} />
                    <span style={{ fontSize: '12px', color: '#10b981', fontWeight: 800, letterSpacing: '0.5px' }}>Online</span>
                  </div>
                </div>
                {emailCreatedAt && (
                  <div style={{ background: 'rgba(0,0,0,0.3)', padding: '6px 12px', borderRadius: '100px', display: 'flex', alignItems: 'center', gap: '6px', border: '1px solid rgba(255,255,255,0.1)' }}>
                    <Timer size={12} color="rgba(255,255,255,0.7)" />
                    <span style={{ fontSize: '12px', fontWeight: 800, color: timerPercent < 20 ? '#ef4444' : '#fff', fontFamily: 'var(--font-mono)' }}>{timerText}</span>
