                <input className="input-style" type="text" placeholder="Custom alias (optional)" value={customName} onChange={e => setCustomName(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleProvision()} />
                <select className="input-style" style={{ fontSize: '12px', fontWeight: 700, padding: '12px 8px' }} value={selectedDomain} onChange={e => setSelectedDomain(e.target.value)}>
