              </div>
              <button className={`btn-primary btn-glow ${generateSuccess ? 'animate-success' : ''}`} style={{ background: generateSuccess ? 'var(--success)' : 'var(--primary)' }} onClick={handleProvision} disabled={isGenerating}>
                <span style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                  {generateSuccess ? <><Check size={18} /> Generated!</> : isGenerating ? <><motion.span animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 0.8, ease: 'linear' }} style={{ display: 'inline-flex' }}><RefreshCw size={16} /></motion.span> Generating...</> : <><Plus size={16} /> Generate Email</>}
                </span>
