                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '14px' }}>
                  {[
                    { label: 'NAME', val: fakeIdentity.name },
                    { label: 'GENDER', val: fakeIdentity.gender },
                    { label: 'DOB', val: fakeIdentity.dob },
                    { label: 'COUNTRY', val: fakeIdentity.country },
                    { label: 'PHONE', val: fakeIdentity.phone },
                    { label: 'IC/ID NUMBER', val: fakeIdentity.ic },
