                      </div>
                      <button onClick={() => handleDeleteEmail(em)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-muted)', padding: '6px', flexShrink: 0 }}>
                        <Trash2 size={14} />
                      </button>
                    </div>
