              <button className="btn-gh hover-lift" style={{ padding: '10px 14px', background: 'var(--white)', border: '1px solid var(--gray-border)', borderRadius: '12px', boxShadow: '0 2px 8px rgba(0,0,0,0.02)' }} onClick={handleRefreshInbox} disabled={isRefreshing}>
                <RefreshCw size={14} style={{ animation: isRefreshing ? 'spin 0.8s linear infinite' : 'none', color: 'var(--text-main)' }} />
              </button>
