            {currentEmail && (
              <div style={{ padding: '12px 16px', background: 'var(--white)', borderRadius: '16px', marginBottom: '24px', fontSize: '13px', fontWeight: 700, fontFamily: 'var(--font-mono)', color: 'var(--text-sub)', display: 'flex', alignItems: 'center', gap: '10px', border: '1px solid var(--gray-border)', boxShadow: '0 4px 12px rgba(0,0,0,0.02)' }}>
                <span className="live-dot" style={{ width: '8px', height: '8px' }} />
