            <div className="card-premium" style={{ marginTop: '16px' }}>
              <div className="section-label">YOUR API KEY</div>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '10px' }}>
                <code style={{ fontSize: '11px', fontWeight: 600, wordBreak: 'break-all', color: 'var(--text-sub)', flex: 1, fontFamily: 'var(--font-mono)' }}>{profile?.id}</code>
