              onClick={e => e.stopPropagation()}
              style={{ width: '100%', maxWidth: '800px', height: '85vh', background: 'var(--white)', borderTopLeftRadius: '32px', borderTopRightRadius: '32px', display: 'flex', flexDirection: 'column', boxShadow: '0 -20px 40px rgba(0,0,0,0.15)' }}>

              {/* Modal Header */}
              <div style={{ padding: '24px 32px', borderBottom: '1px solid var(--gray-border)', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexShrink: 0 }}>
                <div style={{ flex: 1, paddingRight: '20px' }}>
                  <h2 style={{ fontSize: 'clamp(18px, 4vw, 24px)', fontWeight: 900, color: 'var(--text-main)', marginBottom: '16px', lineHeight: 1.3 }}>{selectedEmail.subject || '(No subject)'}</h2>

                  <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                    <div style={{ width: '42px', height: '42px', background: 'var(--primary-light)', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--primary)', fontWeight: 900, fontSize: '18px', flexShrink: 0 }}>
                      {selectedEmail.sender?.charAt(0).toUpperCase() || '?'}
