                <button onClick={() => setSelectedEmail(null)} style={{ background: 'var(--gray-bg)', border: 'none', width: '36px', height: '36px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', color: 'var(--text-main)', transition: 'all 0.2s', flexShrink: 0 }} className="hover-lift">
                  <X size={18} />
