                  {selectedEmail.html_content
                    ? <iframe srcDoc={selectedEmail.html_content} style={{ width: '100%', height: '60vh', border: 'none' }} title="Email content" sandbox="allow-same-origin allow-popups allow-popups-to-escape-sandbox" />
                    : <pre style={{ whiteSpace: 'pre-wrap', fontSize: '14px', lineHeight: 1.8, fontFamily: 'var(--font-mono)', color: 'var(--text-main)' }}>{selectedEmail.text_content}</pre>
