}
// ===== CLOUD DRIVE COMPONENT (GOD-TIER) =====
function CloudDriveComponent({ user, profile, toast }) {
  const [files, setFiles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [uploading, setUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);

  // Folder Navigation State
  const [currentFolder, setCurrentFolder] = useState('root');
  const [folderHistory, setFolderHistory] = useState([{ id: 'root', name: 'Home' }]);

  // Advanced Upload Modal State
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [uploadType, setUploadType] = useState('local'); // 'local' or 'remote'
  const [selectedFile, setSelectedFile] = useState(null);
  const [remoteUrl, setRemoteUrl] = useState('');

  const [advSettings, setAdvSettings] = useState({
    password: '',
    burnAfterRead: false,
    isPublic: false
  });

  const fetchFiles = useCallback(async () => {
    if (!user) return;
    setLoading(true);
    try {
      const res = await fetch(`${WEB_API}/cloud/files?userId=${user.id}&folderId=${currentFolder}`);
      const json = await res.json();
      if (json.success) setFiles(json.files || []);
    } catch { }
    setLoading(false);
  }, [user, currentFolder]);

  useEffect(() => { fetchFiles(); }, [fetchFiles]);

  const handleCreateFolder = async () => {
    const name = prompt('Enter folder name:');
    if (!name) return;
    try {
      const res = await fetch(`${WEB_API}/cloud/folders`, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId: user.id, name, parentId: currentFolder === 'root' ? null : currentFolder })
      });
      const json = await res.json();
      if (json.success) { toast.success('Folder created'); fetchFiles(); }
      else toast.error(json.error);
    } catch { toast.error('Network error'); }
  };

  const handleAdvUpload = async () => {
    if (uploadType === 'local' && !selectedFile) return toast.error('Please select a file');
    if (uploadType === 'remote' && !remoteUrl) return toast.error('Please enter a URL');

    setUploading(true);
    setUploadProgress(0);

    const formData = new FormData();
    formData.append('userId', user.id);
    formData.append('folderId', currentFolder === 'root' ? '' : currentFolder);
    formData.append('password', advSettings.password);
    formData.append('burnAfterRead', advSettings.burnAfterRead);
    formData.append('isPublic', advSettings.isPublic);

    if (uploadType === 'local') {
      formData.append('file', selectedFile);
      try {
        const xhr = new XMLHttpRequest();
        xhr.open('POST', `${WEB_API}/cloud/upload`, true);
        xhr.upload.onprogress = (ev) => {
          if (ev.lengthComputable) setUploadProgress(Math.round((ev.loaded / ev.total) * 100));
        };
        xhr.onload = function () {
          const json = JSON.parse(xhr.responseText);
          if (json.success) { toast.success('File uploaded!'); fetchFiles(); setShowUploadModal(false); }
          else toast.error(json.error || 'Upload failed');
          setUploading(false);
        };
        xhr.onerror = function () { toast.error('Network error'); setUploading(false); };
        xhr.send(formData);
      } catch { toast.error('Upload failed'); setUploading(false); }
    } else {
      // Remote Leech
      formData.append('url', remoteUrl);
      // Convert FormData to JSON for remote upload
      const payload = Object.fromEntries(formData.entries());
      try {
        setUploadProgress(50); // Fake progress for remote
        const res = await fetch(`${WEB_API}/cloud/remote-upload`, {
          method: 'POST', headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload)
        });
        const json = await res.json();
        if (json.success) { toast.success('File leeched successfully!'); fetchFiles(); setShowUploadModal(false); }
        else toast.error(json.error || 'Remote upload failed');
      } catch { toast.error('Network error'); }
      setUploading(false);
    }
  };

  const handleDelete = async (fileId) => {
    if (!confirm('Delete this permanently?')) return;
    try {
      const res = await fetch(`${WEB_API}/cloud/files/${fileId}`, {
        method: 'DELETE', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId: user.id }),
      });
      const json = await res.json();
      if (json.success) { toast.success('Deleted'); fetchFiles(); }
      else toast.error(json.error);
    } catch { toast.error('Network error'); }
  };

  const formatSize = (bytes) => {
    if (!bytes) return '0 B';
    if (bytes < 1024) return bytes + ' B';
    else if (bytes < 1048576) return (bytes / 1024).toFixed(1) + ' KB';
    else return (bytes / 1048576).toFixed(1) + ' MB';
  };

  const totalUsedBytes = files.reduce((acc, f) => acc + (Number(f.file_size) || 0), 0);
  let maxBytes = 100 * 1024 * 1024 * 1024;
  let limitLabel = '100 GB';
  if (profile?.plan === 'Owner') { maxBytes = 1000 * 1024 * 1024 * 1024 * 1024; limitLabel = 'Unlimited'; }
  else if (profile?.plan === 'VVIP') { maxBytes = 5 * 1024 * 1024 * 1024 * 1024; limitLabel = '5 TB'; }
  else if (profile?.plan === 'Pro') { maxBytes = 1 * 1024 * 1024 * 1024 * 1024; limitLabel = '1 TB'; }

  const storagePercent = profile?.plan === 'Owner' ? 0 : Math.min((totalUsedBytes / maxBytes) * 100, 100);

  return (
    <div style={{ paddingBottom: '40px' }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '20px' }}>
        <div style={{ width: '40px', height: '40px', background: '#0ea5e915', border: '1px solid #0ea5e940', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Cloud size={20} color="#0ea5e9" />
        </div>
        <div style={{ flex: 1 }}>
          <h2 style={{ fontSize: '20px', fontWeight: 900, margin: 0, color: 'var(--text-main)' }}>Cloud Drive</h2>
          <span style={{ fontSize: '12px', color: 'var(--text-muted)' }}>Secure distributed storage</span>
        </div>
        <div style={{ background: 'var(--gray-bg)', padding: '6px 12px', borderRadius: '10px', border: '1px solid var(--gray-border)' }}>
          <div style={{ fontSize: '10px', fontWeight: 800, color: 'var(--text-sub)', marginBottom: '2px', textTransform: 'uppercase' }}>{profile?.plan} Plan Limit</div>
          <div style={{ fontSize: '13px', fontWeight: 800, color: 'var(--primary)' }}>{formatSize(totalUsedBytes)} / {limitLabel}</div>
        </div>
      </div>

      {profile?.plan !== 'Owner' && (
        <div style={{ width: '100%', height: '6px', background: 'var(--gray-border)', borderRadius: '4px', marginBottom: '24px', overflow: 'hidden' }}>
          <motion.div initial={{ width: 0 }} animate={{ width: `${storagePercent}%` }} style={{ height: '100%', background: storagePercent > 90 ? 'var(--danger)' : 'var(--primary)' }} transition={{ duration: 1 }} />
        </div>
      )}

      {/* Toolbar */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', background: 'var(--white)', padding: '12px', borderRadius: '16px', border: '1px solid var(--gray-border)', boxShadow: '0 4px 20px rgba(0,0,0,0.02)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', overflowX: 'auto' }} className="hide-scrollbar">
          {folderHistory.map((hist, i) => (
            <React.Fragment key={hist.id}>
              <button onClick={() => {
                const newHist = folderHistory.slice(0, i + 1);
                setFolderHistory(newHist);
                setCurrentFolder(hist.id);
              }} style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: '13px', fontWeight: 700, color: i === folderHistory.length - 1 ? 'var(--text-main)' : 'var(--text-muted)' }}>
                {hist.name}
              </button>
              {i < folderHistory.length - 1 && <ChevronRight size={14} color="var(--gray-400)" />}
            </React.Fragment>
          ))}
        </div>
        <div style={{ display: 'flex', gap: '8px' }}>
          <button className="btn-gh" onClick={handleCreateFolder} style={{ padding: '8px 12px', fontSize: '12px' }}><Plus size={14} /> New Folder</button>
          <button className="btn-primary" onClick={() => { setUploadType('local'); setShowUploadModal(true); }} style={{ padding: '8px 16px', fontSize: '12px', display: 'flex', alignItems: 'center', gap: '6px', borderRadius: '10px' }}>
            <UploadCloud size={14} /> Upload
          </button>
        </div>
      </div>

      {/* File List */}
      <div>
        {loading ? (
          <div style={{ textAlign: 'center', padding: '60px', color: 'var(--text-muted)' }}><RefreshCw size={24} className="spinner-icon" /></div>
        ) : files.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '60px 20px', background: 'var(--white)', border: '1px dashed var(--gray-300)', borderRadius: '24px' }}>
            <div style={{ width: '64px', height: '64px', background: 'var(--gray-bg)', borderRadius: '16px', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 16px' }}>
              <FileText size={28} color="var(--gray-400)" />
            </div>
            <div style={{ fontSize: '16px', fontWeight: 800, color: 'var(--text-main)', marginBottom: '4px' }}>This folder is empty</div>
            <div style={{ fontSize: '13px', color: 'var(--text-sub)' }}>Upload files or create a new folder here.</div>
          </div>
        ) : (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '16px' }}>
            {files.map(f => (
              <motion.div key={f.id} initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }}
                onDoubleClick={() => {
                  if (f.is_folder) {
                    setCurrentFolder(f.id);
                    setFolderHistory([...folderHistory, { id: f.id, name: f.file_name }]);
                  }
                }}
                style={{ padding: '16px', background: 'var(--white)', border: '1px solid var(--gray-border)', borderRadius: '20px', boxShadow: '0 4px 12px rgba(0,0,0,0.02)', cursor: f.is_folder ? 'pointer' : 'default', transition: 'all 0.2s', position: 'relative' }} className="hover-lift">

                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '12px' }}>
                  <div style={{ width: '40px', height: '40px', background: f.is_folder ? '#0ea5e915' : 'var(--gray-bg)', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                    {f.is_folder ? <Box size={20} color="#0ea5e9" /> : <FileText size={20} color="var(--text-sub)" />}
                  </div>
                  <div style={{ display: 'flex', gap: '4px' }}>
                    {f.password_hash && <Lock size={12} color="#f59e0b" />}
                    {f.burn_after_read && <Zap size={12} color="#ef4444" />}
                    {f.is_public && <Globe size={12} color="#10b981" />}
                  </div>
                </div>

                <div style={{ fontWeight: 800, fontSize: '13px', color: 'var(--text-main)', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', marginBottom: '4px' }} title={f.file_name}>{f.file_name}</div>
                <div style={{ fontSize: '11px', color: 'var(--text-muted)', marginBottom: '16px' }}>
                  {f.is_folder ? 'Folder' : formatSize(f.file_size)} • {new Date(f.created_at).toLocaleDateString()}
                </div>

                {!f.is_folder && (
                  <div style={{ display: 'flex', gap: '6px', borderTop: '1px solid var(--gray-border)', paddingTop: '12px' }}>
                    <button onClick={() => navigator.clipboard.writeText(`${WEB_API}/cloud/download/${f.id}`)} style={{ flex: 1, background: 'var(--gray-bg)', color: 'var(--text-sub)', border: 'none', padding: '6px', borderRadius: '8px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }} title="Copy Link">
                      <Link2 size={14} />
                    </button>
                    <a href={`${WEB_API}/cloud/download/${f.id}`} target="_blank" rel="noopener noreferrer" style={{ flex: 1, background: '#10b98115', color: '#10b981', border: 'none', padding: '6px', borderRadius: '8px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }} title="Download">
                      <Download size={14} />
                    </a>
                    <button onClick={() => handleDelete(f.id)} style={{ flex: 1, background: '#ef444415', color: '#ef4444', border: 'none', padding: '6px', borderRadius: '8px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }} title="Delete">
                      <Trash2 size={14} />
                    </button>
                  </div>
                )}
                {f.is_folder && (
                  <div style={{ display: 'flex', borderTop: '1px solid var(--gray-border)', paddingTop: '12px' }}>
                    <button onClick={(e) => { e.stopPropagation(); handleDelete(f.id); }} style={{ flex: 1, background: '#ef444415', color: '#ef4444', border: 'none', padding: '6px', borderRadius: '8px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }} title="Delete Folder">
                      <Trash2 size={14} /> Delete
                    </button>
                  </div>
                )}
