                <h3 style={{ fontSize: '18px', fontWeight: 900, margin: 0 }}>Secure Upload</h3>
                <button onClick={() => !uploading && setShowUploadModal(false)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-muted)' }}><X size={20} /></button>
              </div>

              <div style={{ display: 'flex', gap: '8px', marginBottom: '20px', background: 'var(--gray-bg)', padding: '4px', borderRadius: '10px' }}>
                <button onClick={() => setUploadType('local')} style={{ flex: 1, padding: '8px', borderRadius: '8px', border: 'none', background: uploadType === 'local' ? 'var(--white)' : 'transparent', color: uploadType === 'local' ? 'var(--text-main)' : 'var(--text-muted)', fontWeight: 700, fontSize: '12px', boxShadow: uploadType === 'local' ? '0 2px 8px rgba(0,0,0,0.05)' : 'none' }}>Local File</button>
                <button onClick={() => setUploadType('remote')} style={{ flex: 1, padding: '8px', borderRadius: '8px', border: 'none', background: uploadType === 'remote' ? 'var(--white)' : 'transparent', color: uploadType === 'remote' ? 'var(--text-main)' : 'var(--text-muted)', fontWeight: 700, fontSize: '12px', boxShadow: uploadType === 'remote' ? '0 2px 8px rgba(0,0,0,0.05)' : 'none' }}>Remote URL</button>
              </div>

              {uploadType === 'local' ? (
                <div style={{ background: 'var(--gray-bg)', border: '1px dashed var(--gray-400)', borderRadius: '16px', padding: '24px', textAlign: 'center', marginBottom: '20px', position: 'relative' }}>
                  <input type="file" onChange={e => setSelectedFile(e.target.files?.[0])} style={{ position: 'absolute', inset: 0, opacity: 0, cursor: 'pointer' }} />
                  <UploadCloud size={24} color="var(--primary)" style={{ marginBottom: '8px' }} />
                  <div style={{ fontSize: '13px', fontWeight: 700 }}>{selectedFile ? selectedFile.name : 'Select a file to upload'}</div>
                </div>
              ) : (
                <div style={{ marginBottom: '20px' }}>
                  <label style={{ fontSize: '11px', fontWeight: 800, color: 'var(--text-sub)', marginBottom: '6px', display: 'block' }}>Direct Download URL</label>
                  <input type="url" className="input-style" placeholder="https://example.com/file.zip" value={remoteUrl} onChange={e => setRemoteUrl(e.target.value)} />
                </div>
              )}

              <div style={{ background: 'var(--gray-bg)', borderRadius: '16px', padding: '16px', display: 'flex', flexDirection: 'column', gap: '12px', marginBottom: '24px' }}>
                <div style={{ fontSize: '11px', fontWeight: 800, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.5px' }}>Security Settings</div>

                <div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '6px' }}>
                    <Lock size={14} color="#f59e0b" />
                    <span style={{ fontSize: '13px', fontWeight: 700 }}>Password Protect</span>
                  </div>
                  <input type="text" className="input-style" placeholder="Optional password" value={advSettings.password} onChange={e => setAdvSettings({...advSettings, password: e.target.value})} style={{ padding: '8px 12px', fontSize: '12px' }} />
                </div>

                <label style={{ display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer' }}>
                  <input type="checkbox" checked={advSettings.burnAfterRead} onChange={e => setAdvSettings({...advSettings, burnAfterRead: e.target.checked})} />
                  <div>
                    <div style={{ fontSize: '13px', fontWeight: 700, color: advSettings.burnAfterRead ? '#ef4444' : 'var(--text-main)', display: 'flex', alignItems: 'center', gap: '6px' }}>
                      <Zap size={14} /> Burn After Read
                    </div>
                    <div style={{ fontSize: '11px', color: 'var(--text-muted)' }}>Auto-delete after 1 download</div>
                  </div>
                </label>

                <label style={{ display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer' }}>
                  <input type="checkbox" checked={advSettings.isPublic} onChange={e => setAdvSettings({...advSettings, isPublic: e.target.checked})} />
                  <div>
                    <div style={{ fontSize: '13px', fontWeight: 700, color: advSettings.isPublic ? '#10b981' : 'var(--text-main)', display: 'flex', alignItems: 'center', gap: '6px' }}>
                      <Globe size={14} /> Public / Pay-Per-Download
                    </div>
                    <div style={{ fontSize: '11px', color: 'var(--text-muted)' }}>Earn tokens when others download</div>
                  </div>
                </label>
              </div>

              {uploading ? (
                <div style={{ textAlign: 'center' }}>
                  <div style={{ fontSize: '13px', fontWeight: 800, marginBottom: '8px' }}>Processing... {uploadProgress}%</div>
                  <div style={{ height: '6px', background: 'var(--gray-200)', borderRadius: '100px', overflow: 'hidden' }}>
                    <motion.div initial={{ width: 0 }} animate={{ width: `${uploadProgress}%` }} style={{ height: '100%', background: 'var(--primary)' }} />
                  </div>
                </div>
              ) : (
                <button className="btn-primary" onClick={handleAdvUpload} style={{ width: '100%', padding: '14px', borderRadius: '12px', fontSize: '14px', fontWeight: 800 }}>
                  Upload File
                </button>
              )}
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import { Mail, ArrowLeft } from 'lucide-react';
import { Capacitor } from '@capacitor/core';
import { Browser } from '@capacitor/browser';
import { motion } from 'framer-motion';

export default function AuthPage() {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session) navigate('/app');
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session) navigate('/app');
    });

    if (Capacitor.isNativePlatform()) {
      const handleUrl = async () => {
        const { App } = await import('@capacitor/app');
        App.addListener('appUrlOpen', async ({ url }) => {
          if (url.includes('access_token') || url.includes('code=')) {
            const hashPart = url.split('#')[1] || url.split('?')[1];
            if (hashPart) {
              const params = new URLSearchParams(hashPart);
              const accessToken = params.get('access_token');
              const refreshToken = params.get('refresh_token');
              if (accessToken && refreshToken) {
                await supabase.auth.setSession({ access_token: accessToken, refresh_token: refreshToken });
              }
            }
            await Browser.close();
          }
        });
      };
      handleUrl();
    }

    return () => subscription.unsubscribe();
  }, [navigate]);

  const handleSocialLogin = async (provider) => {
    setLoading(true);
    try {
      if (Capacitor.isNativePlatform()) {
        const { data, error } = await supabase.auth.signInWithOAuth({
          provider,
          options: {
            redirectTo: 'com.cexistore.app://login-callback',
            skipBrowserRedirect: true,
          }
        });
        if (error) throw error;
        if (data?.url) {
          await Browser.open({ url: data.url, windowName: '_self' });
        }
      } else {
        const { error } = await supabase.auth.signInWithOAuth({
          provider,
          options: {
            redirectTo: `${window.location.origin}/app`
          }
        });
        if (error) throw error;
      }
    } catch (e) {
      alert('Error: ' + e.message);
    }
    setLoading(false);
  };

  return (
    <div className="mesh-bg" style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '20px', position: 'relative' }}>

      <button onClick={() => navigate('/')} style={{ position: 'absolute', top: '24px', left: '24px', background: 'var(--white)', border: '1px solid var(--gray-border)', borderRadius: '12px', padding: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', color: 'var(--text-main)', boxShadow: '0 4px 12px rgba(0,0,0,0.05)' }} className="hover-lift">
        <ArrowLeft size={20} />
      </button>

      <motion.div
        initial={{ opacity: 0, y: 30, scale: 0.95 }}
        animate={{ opacity: 1, y: 0, scale: 1 }}
        transition={{ type: 'spring', stiffness: 100, damping: 20 }}
        className="glass-panel"
        style={{ width: '100%', maxWidth: '400px', padding: '48px 32px', textAlign: 'center' }}>

        <motion.div animate={{ y: [0, -5, 0] }} transition={{ duration: 4, repeat: Infinity, ease: 'easeInOut' }}
          style={{ width: '64px', height: '64px', background: 'var(--black)', borderRadius: '18px', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 24px', boxShadow: '0 10px 30px rgba(0,0,0,0.1)' }}>
          <Mail size={28} style={{ color: 'var(--white)' }} />
        </motion.div>

        <h1 style={{ fontSize: '28px', fontWeight: 900, letterSpacing: '-1px', marginBottom: '8px', color: 'var(--text-main)' }}>Welcome back</h1>
        <p style={{ fontSize: '14px', color: 'var(--text-sub)', marginBottom: '36px', lineHeight: 1.6 }}>Sign in to access your premium digital identity toolkit.</p>

        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
          <button
            onClick={() => handleSocialLogin('github')}
            disabled={loading}
            className="btn-primary hover-lift"
            style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px', padding: '14px', fontSize: '14px', borderRadius: '12px', boxShadow: '0 8px 20px rgba(0,0,0,0.1)' }}
          >
            <svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor"><path d="M12 0C5.37 0 0 5.37 0 12c0 5.31 3.435 9.795 8.205 11.385.6.105.825-.255.825-.57 0-.285-.015-1.23-.015-2.235-3.015.555-3.795-.735-4.035-1.41-.135-.345-.72-1.41-1.23-1.695-.42-.225-1.02-.78-.015-.795.945-.015 1.62.87 1.845 1.23 1.08 1.815 2.805 1.305 3.495.99.105-.78.42-1.305.765-1.605-2.67-.3-5.46-1.335-5.46-5.925 0-1.305.465-2.385 1.23-3.225-.12-.3-.54-1.53.12-3.18 0 0 1.005-.315 3.3 1.23.96-.27 1.98-.405 3-.405s2.04.135 3 .405c2.295-1.56 3.3-1.23 3.3-1.23.66 1.65.24 2.88.12 3.18.765.84 1.23 1.905 1.23 3.225 0 4.605-2.805 5.625-5.475 5.925.435.375.81 1.095.81 2.22 0 1.605-.015 2.895-.015 3.3 0 .315.225.69.825.57A12.02 12.02 0 0024 12c0-6.63-5.37-12-12-12z"/></svg>
            {loading ? 'Connecting...' : 'Continue with GitHub'}
          </button>

          <button
            onClick={() => handleSocialLogin('google')}
            disabled={loading}
            className="hover-lift"
            style={{ width: '100%', padding: '14px', borderRadius: '12px', background: 'rgba(255,255,255,0.9)', color: '#111', border: '1px solid var(--gray-border)', fontSize: '14px', fontWeight: 800, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px', boxShadow: '0 4px 12px rgba(0,0,0,0.02)' }}
          >
            <svg width="18" height="18" viewBox="0 0 24 24"><path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 01-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z" fill="#4285F4"/><path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/><path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/><path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/></svg>
            {loading ? 'Connecting...' : 'Continue with Google'}
          </button>
        </div>

        <p style={{ marginTop: '36px', fontSize: '12px', color: 'var(--text-muted)' }}>
          By signing in, you agree to our <a href="/terms" style={{ color: 'var(--primary)', fontWeight: 700, textDecoration: 'none' }}>Terms of Service</a>.
        </p>
      </motion.div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import { useToast } from '../components/Toast';
import { motion } from 'framer-motion';
import {
  Server, ArrowLeft, Mail, User, HardDrive, Network, Egg,
  CheckCircle, Loader2, Zap, Crown, AlertCircle, Copy
} from 'lucide-react';

const WEB_API = window.location.origin + '/api/web';
const PREMIUM_PLANS = ['Pro', 'VVIP', 'Owner'];

export default function HostingPage() {
  const navigate = useNavigate();
  const toast = useToast();
  const [user, setUser] = useState(null);
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [orderResult, setOrderResult] = useState(null);

  const [nodes, setNodes] = useState([]);
  const [eggs, setEggs] = useState([]);

  const [form, setForm] = useState({
    email: '', username: '', node: '', allocation: 'default', egg: '', sendTo: '',
  });

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (!session) { navigate('/auth'); return; }
      setUser(session.user);

      Promise.all([
        fetch(`${WEB_API}/profile?userId=${session.user.id}`).then(r => r.json()),
        fetch(`${WEB_API}/admin/nodes`).then(r => r.json()),
        fetch(`${WEB_API}/admin/eggs`).then(r => r.json())
      ]).then(([profRes, nodesRes, eggsRes]) => {
        if (profRes.success) {
          setProfile(profRes.profile);
          setForm(f => ({ ...f, email: session.user.email || '', sendTo: session.user.email || '' }));
        }
        if (nodesRes.success && nodesRes.nodes.length > 0) {
          setNodes(nodesRes.nodes);
          setForm(f => ({ ...f, node: nodesRes.nodes[0].id }));
        }
        if (eggsRes.success) {
          setEggs(eggsRes.eggs);
        }
      }).finally(() => setLoading(false));
    });
  }, [navigate]);

  const updateField = (key, val) => setForm(f => ({ ...f, [key]: val }));

  const handleSubmit = async () => {
    if (!form.email.trim() || !form.username.trim() || !form.egg) {
      toast.error('Please fill all required fields');
      return;
    }
    if ((profile?.tokens || 0) < 5) {
      toast.error('Need at least 5 tokens for hosting');
      return;
    }
    setSubmitting(true);
    try {
      const res = await fetch(`${WEB_API}/ptero-order`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId: user.id, ...form }),
      });
      const json = await res.json();
      if (json.success) {
        setOrderResult(json.order);
        setProfile(p => ({ ...p, tokens: (p?.tokens || 0) - 5 }));
        toast.success('Panel created! Credentials sent to your email.');
      } else {
        toast.error(json.error || 'Order failed');
      }
    } catch { toast.error('Network error'); }
    setSubmitting(false);
  };

  const copyText = (text) => { navigator.clipboard.writeText(text); toast.success('Copied!'); };

  if (loading) {
    return (
      <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'var(--white)' }}>
        <div className="spinner" />
      </div>
    );
  }

  return (
    <div style={{ minHeight: '100vh', background: 'var(--white)', color: 'var(--text-main)' }}>
      <div style={{ maxWidth: '640px', margin: '0 auto', padding: '30px 20px 80px' }}>

        <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '28px' }}>
          <button onClick={() => navigate('/app')}
            style={{ background: 'var(--gray-bg)', border: 'none', borderRadius: '10px', padding: '8px', cursor: 'pointer', display: 'flex' }}>
            <ArrowLeft size={18} style={{ color: 'var(--text-main)' }} />
          </button>
          <div style={{ flex: 1 }}>
            <h1 style={{ fontSize: '22px', fontWeight: 900, letterSpacing: '-0.5px' }}>Hosting Panel</h1>
            <p style={{ fontSize: '12px', color: 'var(--text-muted)', fontWeight: 600 }}>Pterodactyl game & app hosting</p>
          </div>
          <div style={{ background: 'var(--gray-bg)', borderRadius: 'var(--radius-md)', padding: '6px 12px', display: 'flex', alignItems: 'center', gap: '6px' }}>
            <Zap size={12} style={{ color: 'var(--primary)' }} />
            <span style={{ fontSize: '12px', fontWeight: 800 }}>{profile?.tokens || 0}</span>
          </div>
        </div>

        {orderResult ? (
          <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }}>
            <div style={{ textAlign: 'center', marginBottom: '24px' }}>
              <div style={{ width: '64px', height: '64px', background: 'var(--success)', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 16px', boxShadow: '0 0 40px rgba(16,185,129,0.3)' }}>
                <CheckCircle size={32} color="#fff" />
              </div>
              <h2 style={{ fontSize: '20px', fontWeight: 900, marginBottom: '6px' }}>Panel Created!</h2>
              <p style={{ fontSize: '13px', color: 'var(--text-sub)' }}>
                Credentials have been sent to <strong>{orderResult.sentTo}</strong>
              </p>
            </div>

            <div style={{ padding: '20px', background: 'var(--gray-bg)', borderRadius: 'var(--radius-xl)', marginBottom: '16px' }}>
              {[
                ['Server ID', orderResult.serverId],
                ['Panel URL', 'panel.cexistore.com'],
                ['Email', orderResult.email],
                ['Username', orderResult.username],
                ['Password', orderResult.password],
                ['Node', orderResult.node],
                ['Egg', orderResult.egg],
              ].map(([label, value]) => (
                <div key={label} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '8px 0', borderBottom: '1px solid var(--gray-border)' }}>
                  <span style={{ fontSize: '12px', color: 'var(--text-muted)', fontWeight: 600 }}>{label}</span>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <code style={{ fontSize: '13px', fontWeight: 700, fontFamily: 'var(--font-mono)' }}>{value}</code>
                    <button onClick={() => copyText(value)}
                      style={{ background: 'none', border: 'none', cursor: 'pointer', padding: '2px', color: 'var(--text-muted)', display: 'flex' }}>
                      <Copy size={12} />
                    </button>
                  </div>
                </div>
              ))}
            </div>

            {!orderResult.emailSent && (
              <div style={{ padding: '12px 16px', background: '#fef3c7', borderRadius: 'var(--radius-md)', display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '16px' }}>
                <AlertCircle size={16} style={{ color: '#f59e0b' }} />
                <span style={{ fontSize: '12px', fontWeight: 600, color: '#92400e' }}>Email delivery pending. Save your credentials above.</span>
              </div>
            )}

            <button className="btn-primary" onClick={() => { setOrderResult(null); setForm(f => ({ ...f, username: '', egg: '' })); }}
              style={{ width: '100%', padding: '14px', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', fontSize: '14px' }}>
              <Server size={16} /> Create Another Panel
            </button>
          </motion.div>
        ) : (
          <motion.div initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }}>
            <div style={{ padding: '16px', background: 'linear-gradient(135deg, #0066ff10, #0ea5e910)', border: '2px solid var(--gray-border)', borderRadius: 'var(--radius-xl)', marginBottom: '20px' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '8px' }}>
                <Server size={20} style={{ color: 'var(--primary)' }} />
                <span style={{ fontSize: '14px', fontWeight: 800 }}>Pterodactyl Panel</span>
              </div>
              <p style={{ fontSize: '12px', color: 'var(--text-sub)', lineHeight: 1.5, marginBottom: '8px' }}>
                Create your own game or application server. Credentials will be emailed to you. Cost: 5 tokens per panel.
              </p>
              {(profile?.tokens || 0) < 5 && (
                <div style={{ padding: '10px 14px', background: '#fee2e2', borderRadius: 'var(--radius-md)', display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <AlertCircle size={14} style={{ color: '#ef4444' }} />
                  <span style={{ fontSize: '12px', fontWeight: 600, color: '#991b1b' }}>Insufficient tokens. You need at least 5 tokens.</span>
                </div>
              )}
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
              <div>
                <label style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '13px', fontWeight: 700, marginBottom: '8px' }}>
                  <Mail size={14} style={{ color: 'var(--text-muted)' }} /> Panel Email *
                </label>
                <input className="input-style" type="email" placeholder="your@email.com" value={form.email}
                  onChange={e => updateField('email', e.target.value)}
                  style={{ width: '100%', padding: '12px 14px', borderRadius: 'var(--radius-md)', border: '1px solid var(--gray-border)', background: 'var(--white)', color: 'var(--text-main)', fontSize: '13px', boxSizing: 'border-box' }} />
              </div>

              <div>
                <label style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '13px', fontWeight: 700, marginBottom: '8px' }}>
                  <User size={14} style={{ color: 'var(--text-muted)' }} /> Username *
