import React, { useState, useEffect, useRef } from 'react';
import { supabase } from '../lib/supabase';
import { useToast } from '../components/Toast';
import { motion, AnimatePresence, useInView } from 'framer-motion';
import {
  Crown, Zap, Shield, CheckCircle, ArrowRight, Sparkles, Star,
  Copy, Smartphone, CreditCard, MessageCircle
} from 'lucide-react';

const WEB_API = window.location.origin + '/api/web';

const PLANS = [
  {
    id: 'standard', name: 'Standard', price: 'RM10', tokens: '100 Tokens',
    color: '#0066ff', icon: Zap,
    features: ['100 email tokens', '2 domains', 'Basic inbox', 'Email support', '30 min TTL'],
  },
  {
    id: 'pro', name: 'Pro', price: 'RM25', tokens: '500 Tokens',
    color: '#0ea5e9', icon: Crown, badge: 'POPULAR',
    features: ['500 email tokens', 'All domains', 'Priority inbox', 'Stresser access', 'API access', 'WhatsApp support'],
  },
  {
    id: 'vvip', name: 'VVIP', price: 'RM50', tokens: 'Unlimited',
    color: '#f59e0b', icon: Star, badge: 'BEST VALUE',
    features: ['Unlimited tokens', 'All domains', 'Priority inbox', 'Full stresser', 'Unlimited API', 'Priority support', 'Custom domain'],
  },
];

const PAYMENT_METHODS = [
  { id: 'gopay', name: 'GoPay', icon: Smartphone, color: '#00aed6', account: '6285-1413-08851', label: 'GoPay Number' },
  { id: 'tng', name: "Touch 'n Go", icon: CreditCard, color: '#005abb', account: '011-7134-1399', label: 'TNG Phone Number' },
];

function AnimSection({ children, delay = 0 }) {
  const ref = useRef(null);
  const inView = useInView(ref, { once: true, margin: '-40px' });
  return (
    <motion.div ref={ref} initial={{ opacity: 0, y: 24 }} animate={inView ? { opacity: 1, y: 0 } : {}} transition={{ duration: 0.5, delay }}>
      {children}
    </motion.div>
  );
}

export default function PricingPage() {
  const toast = useToast();
  const [user, setUser] = useState(null);
  const [step, setStep] = useState(1);
  const [selectedPlan, setSelectedPlan] = useState(null);
  const [selectedPayment, setSelectedPayment] = useState(null);
  const [paymentRef, setPaymentRef] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [orderDone, setOrderDone] = useState(false);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => { if (session) setUser(session.user); });
  }, []);

  const copyText = (text) => {
    navigator.clipboard.writeText(text);
    toast.success('Copied!');
  };

  const handleSubmitOrder = async () => {
    if (!user || !selectedPlan || !selectedPayment || !paymentRef.trim()) {
      toast.error('Please fill in payment reference');
      return;
    }
    setSubmitting(true);
    try {
      const plan = PLANS.find(p => p.id === selectedPlan);
      const res = await fetch(`${WEB_API}/order`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          userId: user.id, plan: plan.name,
          amount: parseFloat(plan.price.replace('RM', '')),
          paymentMethod: selectedPayment, paymentRef: paymentRef.trim(),
        }),
      });
      const json = await res.json();
      if (!json.success) { toast.error(json.error || 'Order failed'); setSubmitting(false); return; }
      setOrderDone(true);
      setStep(3);
      toast.success('Order submitted!');
      const msg = encodeURIComponent(
        `*CEXISTORE ORDER*\n\nPlan: ${plan.name} (${plan.price})\nPayment: ${selectedPayment.toUpperCase()}\nRef: ${paymentRef.trim()}\nEmail: ${user.email}\n\nPlease approve my order. Thank you!`
      );
      setTimeout(() => window.open(`https://wa.me/601171341399?text=${msg}`, '_blank'), 1500);
    } catch (e) { toast.error('Network error'); }
    setSubmitting(false);
  };

  const sv = { enter: { opacity: 0, x: 50 }, center: { opacity: 1, x: 0 }, exit: { opacity: 0, x: -50 } };

  return (
    <div style={{ minHeight: '100vh', background: 'var(--white)', color: 'var(--text-main)', transition: 'all 0.4s' }}>
      <div style={{ maxWidth: '860px', margin: '0 auto', padding: '40px 20px 80px' }}>
        <AnimSection>
          <div style={{ textAlign: 'center', marginBottom: '16px' }}>
            <span className="badge badge-ocean" style={{ marginBottom: '12px', display: 'inline-flex', gap: '6px' }}><Sparkles size={12} /> PRICING</span>
            <h1 style={{ fontSize: 'clamp(28px, 5vw, 42px)', fontWeight: 900, letterSpacing: '-1.5px', lineHeight: 1.1, marginBottom: '12px' }}>
              Choose your <span className="gradient-text">power level</span>
            </h1>
            <p style={{ color: 'var(--text-sub)', fontSize: '15px', maxWidth: '420px', margin: '0 auto' }}>
              Upgrade to unlock more tokens, features, and priority support.
            </p>
          </div>
        </AnimSection>

        <div style={{ display: 'flex', justifyContent: 'center', gap: '8px', margin: '28px 0 36px', alignItems: 'center' }}>
          {[1, 2, 3].map(s => (
            <React.Fragment key={s}>
              <motion.div animate={{ scale: step === s ? 1.15 : 1 }}
                style={{ width: '32px', height: '32px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '13px', fontWeight: 800,
                  background: step >= s ? 'var(--primary)' : 'var(--gray-bg)', color: step >= s ? '#fff' : 'var(--text-muted)',
                  transition: 'all 0.3s', boxShadow: step === s ? '0 0 20px rgba(0,102,255,0.4)' : 'none' }}>{s}</motion.div>
              {s < 3 && <div style={{ width: '40px', height: '2px', background: step > s ? 'var(--primary)' : 'var(--gray-border)', transition: 'all 0.3s', borderRadius: '2px' }} />}
            </React.Fragment>
          ))}
        </div>

        <AnimatePresence mode="wait">
          {step === 1 && (
            <motion.div key="s1" variants={sv} initial="enter" animate="center" exit="exit" transition={{ duration: 0.3 }}>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: '16px' }}>
                {PLANS.map((plan, i) => {
                  const Icon = plan.icon;
                  const sel = selectedPlan === plan.id;
                  return (
                    <motion.div key={plan.id} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.1 }}
                      whileHover={{ y: -6, scale: 1.02 }} whileTap={{ scale: 0.98 }}
                      onClick={() => setSelectedPlan(plan.id)}
                      style={{ padding: '28px 24px', borderRadius: 'var(--radius-xl)', cursor: 'pointer',
                        border: sel ? `2px solid ${plan.color}` : '2px solid var(--gray-border)',
                        background: sel ? `${plan.color}08` : 'var(--white)',
                        boxShadow: sel ? `0 8px 32px ${plan.color}20` : '0 2px 8px rgba(0,0,0,0.04)',
                        transition: 'all 0.3s', position: 'relative', overflow: 'hidden' }}>
                      {plan.badge && (
                        <div style={{ position: 'absolute', top: '14px', right: '-28px', transform: 'rotate(45deg)',
                          background: plan.color, color: '#fff', fontSize: '9px', fontWeight: 800, padding: '4px 36px', letterSpacing: '0.5px' }}>{plan.badge}</div>
                      )}
                      <div style={{ width: '44px', height: '44px', background: `${plan.color}15`, borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: '16px' }}>
                        <Icon size={22} style={{ color: plan.color }} />
                      </div>
                      <h3 style={{ fontSize: '18px', fontWeight: 800, marginBottom: '4px' }}>{plan.name}</h3>
                      <div style={{ display: 'flex', alignItems: 'baseline', gap: '4px', marginBottom: '4px' }}>
                        <span style={{ fontSize: '32px', fontWeight: 900, color: plan.color }}>{plan.price}</span>
                        <span style={{ fontSize: '13px', color: 'var(--text-muted)' }}>/one-time</span>
                      </div>
                      <p style={{ fontSize: '13px', color: 'var(--text-sub)', marginBottom: '16px', fontWeight: 600 }}>{plan.tokens}</p>
                      <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                        {plan.features.map(f => (
                          <div key={f} style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '13px', color: 'var(--text-sub)' }}>
                            <CheckCircle size={14} style={{ color: plan.color, flexShrink: 0 }} /> {f}
                          </div>
                        ))}
                      </div>
                      {sel && <motion.div initial={{ scale: 0 }} animate={{ scale: 1 }} style={{ position: 'absolute', top: '12px', left: '12px', width: '24px', height: '24px', borderRadius: '50%', background: plan.color, display: 'flex', alignItems: 'center', justifyContent: 'center' }}><CheckCircle size={14} color="#fff" /></motion.div>}
                    </motion.div>
                  );
                })}
              </div>
              <div style={{ textAlign: 'center', marginTop: '28px' }}>
                <button className="btn-primary btn-glow" disabled={!selectedPlan} onClick={() => { if (!user) { toast.error('Please login first'); return; } if (selectedPlan) setStep(2); }}
                  style={{ padding: '14px 40px', display: 'inline-flex', alignItems: 'center', gap: '8px', fontSize: '15px', opacity: selectedPlan ? 1 : 0.5 }}>
                  Continue <ArrowRight size={16} />
                </button>
              </div>
            </motion.div>
          )}

          {step === 2 && (
            <motion.div key="s2" variants={sv} initial="enter" animate="center" exit="exit" transition={{ duration: 0.3 }}>
              <div style={{ maxWidth: '480px', margin: '0 auto' }}>
                <h2 style={{ fontSize: '20px', fontWeight: 800, marginBottom: '20px', textAlign: 'center' }}>Payment Method</h2>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '12px', marginBottom: '24px' }}>
                  {PAYMENT_METHODS.map(pm => {
                    const Icon = pm.icon;
                    const sel = selectedPayment === pm.id;
                    return (
                      <motion.div key={pm.id} whileHover={{ scale: 1.01 }} whileTap={{ scale: 0.98 }}
                        onClick={() => setSelectedPayment(pm.id)}
                        style={{ padding: '20px', borderRadius: 'var(--radius-md)', cursor: 'pointer',
                          border: sel ? `2px solid ${pm.color}` : '2px solid var(--gray-border)',
                          background: sel ? `${pm.color}08` : 'var(--white)', transition: 'all 0.3s' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '14px' }}>
                          <div style={{ width: '44px', height: '44px', background: `${pm.color}15`, borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                            <Icon size={22} style={{ color: pm.color }} />
                          </div>
                          <div style={{ flex: 1 }}>
                            <div style={{ fontWeight: 700, fontSize: '15px' }}>{pm.name}</div>
                            <div style={{ fontSize: '12px', color: 'var(--text-muted)' }}>{pm.label}</div>
                          </div>
                          {sel && <CheckCircle size={20} style={{ color: pm.color }} />}
                        </div>
                        <AnimatePresence>
                          {sel && (
                            <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} transition={{ duration: 0.3 }}
                              style={{ marginTop: '16px', paddingTop: '16px', borderTop: '1px solid var(--gray-border)' }}>
                              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '12px 16px', background: 'var(--gray-bg)', borderRadius: 'var(--radius-md)' }}>
                                <div>
                                  <div style={{ fontSize: '11px', color: 'var(--text-muted)', fontWeight: 600, marginBottom: '4px' }}>TRANSFER TO</div>
                                  <div style={{ fontSize: '18px', fontWeight: 800, fontFamily: 'var(--font-mono)', letterSpacing: '1px' }}>{pm.account}</div>
                                </div>
                                <button onClick={e => { e.stopPropagation(); copyText(pm.account.replace(/-/g, '')); }}
                                  style={{ background: `${pm.color}15`, border: 'none', borderRadius: '8px', padding: '8px 12px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '6px', fontSize: '12px', fontWeight: 700, color: pm.color }}>
                                  <Copy size={14} /> Copy
                                </button>
                              </div>
                              <p style={{ fontSize: '12px', color: 'var(--text-muted)', marginTop: '10px', textAlign: 'center' }}>
                                Transfer <strong style={{ color: 'var(--text-main)' }}>{PLANS.find(p => p.id === selectedPlan)?.price}</strong> then enter reference below
                              </p>
                            </motion.div>
                          )}
                        </AnimatePresence>
                      </motion.div>
                    );
                  })}
                </div>

                {selectedPayment && (
                  <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} style={{ marginBottom: '20px' }}>
                    <label style={{ fontSize: '13px', fontWeight: 700, display: 'block', marginBottom: '8px' }}>Payment Reference / Transaction ID</label>
                    <input className="input-style" type="text" placeholder="e.g. TNG-20260411-XXXXX" value={paymentRef} onChange={e => setPaymentRef(e.target.value)}
                      style={{ width: '100%', padding: '14px 16px', borderRadius: 'var(--radius-md)', border: '1px solid var(--gray-border)', background: 'var(--white)', color: 'var(--text-main)', fontSize: '14px', boxSizing: 'border-box' }} />
                  </motion.div>
                )}

                {selectedPlan && selectedPayment && (
                  <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                    style={{ padding: '20px', background: 'var(--gray-bg)', borderRadius: 'var(--radius-md)', marginBottom: '20px' }}>
                    <div style={{ fontSize: '13px', fontWeight: 700, marginBottom: '12px' }}>Order Summary</div>
