                      <span style={{ fontWeight: 800 }}>Total</span>
                      <span style={{ fontWeight: 900, color: 'var(--primary)' }}>{PLANS.find(p => p.id === selectedPlan)?.price}</span>
                    </div>
                  </motion.div>
                )}

                <div style={{ display: 'flex', gap: '12px' }}>
