                    style={{ flex: 2, padding: '14px', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', fontSize: '14px', opacity: (!selectedPayment || !paymentRef.trim()) ? 0.5 : 1 }}>
