  { id: 'instagram', name: 'Instagram', color: '#E1306C', icon: '📸' },
  { id: 'youtube', name: 'YouTube', color: '#FF0000', icon: '▶️' },
  { id: 'twitter', name: 'X / Twitter', color: '#1DA1F2', icon: '🐦' },
];

const VIRTUAL_PROVIDERS = [
  { name: 'OnlineSim', url: 'https://onlinesim.io/receive-smss', desc: 'Free virtual numbers for SMS verification', color: '#4CAF50' },
  { name: 'Receive-SMS', url: 'https://receive-smss.com', desc: 'Temporary phone numbers worldwide', color: '#2196F3' },
  { name: 'Temp-Number', url: 'https://temp-number.com', desc: 'Disposable phone numbers for verification', color: '#FF9800' },
