export default function ToolsPage() {
  const navigate = useNavigate();
  const toast = useToast();
  const [user, setUser] = useState(null);
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('downloader');

  const [dlUrl, setDlUrl] = useState('');
  const [dlPlatform, setDlPlatform] = useState('tiktok');
  const [dlLoading, setDlLoading] = useState(false);
  const [dlResult, setDlResult] = useState(null);
  const [dlError, setDlError] = useState('');

  const [genLoading, setGenLoading] = useState(false);
  const [canvaAccount, setCanvaAccount] = useState(null);
  const [alightAccount, setAlightAccount] = useState(null);
  const [genHistory, setGenHistory] = useState(() => {
    try { return JSON.parse(localStorage.getItem('genHistory') || '[]'); } catch { return []; }
  });

  const refreshProfile = () => {
    if (!user) return;
    fetch(`${WEB_API}/profile?userId=${user.id}`)
      .then(r => r.json())
      .then(d => { if (d.success) setProfile(d.profile); });
  };

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (!session) { navigate('/auth'); return; }
      setUser(session.user);
      fetch(`${WEB_API}/profile?userId=${session.user.id}`)
        .then(r => r.json())
        .then(d => { if (d.success) setProfile(d.profile); })
        .finally(() => setLoading(false));
    });
  }, [navigate]);

  const isPremium = PREMIUM_PLANS.includes(profile?.plan);

  const handleDownload = async () => {
    if (!dlUrl.trim()) { toast.error('Please enter a URL'); return; }
    setDlLoading(true); setDlResult(null); setDlError('');
    try {
      const res = await fetch(`${WEB_API}/download`, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId: user.id, url: dlUrl.trim(), platform: dlPlatform }),
      });
      const json = await res.json();
      if (json.success) { setDlResult(json.data); toast.success('Media found!'); }
      else { setDlError(json.error || 'Failed to fetch media'); toast.error(json.error || 'Download failed'); }
    } catch { setDlError('Network error'); toast.error('Network error'); }
    setDlLoading(false);
  };

  const handleGenerate = async (type) => {
    setGenLoading(true);
    try {
      const endpoint = type === 'canva' ? 'generate-canva' : 'generate-alight';
      const res = await fetch(`${WEB_API}/${endpoint}`, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId: user.id }),
      });
      const json = await res.json();
      if (json.success) {
        if (type === 'canva') setCanvaAccount(json.account);
        else setAlightAccount(json.account);
        const entry = { ...json.account, platform: type, time: new Date().toLocaleString() };
        const updated = [entry, ...genHistory].slice(0, 20);
        setGenHistory(updated);
        localStorage.setItem('genHistory', JSON.stringify(updated));
        toast.success(`${type === 'canva' ? 'Canva' : 'Alight Motion'} account generated! (-2 tokens)`);
        refreshProfile();
      } else {
        toast.error(json.error || 'Generation failed');
      }
    } catch { toast.error('Network error'); }
    setGenLoading(false);
  };

  const copyText = (text) => { navigator.clipboard.writeText(text); toast.success('Copied!'); };

  if (loading) {
    return (
      <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'var(--white)' }}>
        <div className="spinner" />
      </div>
    );
  }

  return (
    <div style={{ minHeight: '100vh', background: 'var(--white)', color: 'var(--text-main)' }}>
      <div style={{ maxWidth: '720px', margin: '0 auto', padding: '30px 20px 80px' }}>

        <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '24px' }}>
          <button onClick={() => navigate('/app')}
            style={{ background: 'var(--gray-bg)', border: 'none', borderRadius: '10px', padding: '8px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <ArrowLeft size={18} style={{ color: 'var(--text-main)' }} />
          </button>
          <div style={{ flex: 1 }}>
            <h1 style={{ fontSize: '22px', fontWeight: 900, letterSpacing: '-0.5px' }}>Tools</h1>
            <p style={{ fontSize: '12px', color: 'var(--text-muted)', fontWeight: 600 }}>Downloader, generators & virtual numbers</p>
          </div>
          {profile && (
            <div style={{ background: 'var(--gray-bg)', borderRadius: 'var(--radius-md)', padding: '6px 12px', display: 'flex', alignItems: 'center', gap: '6px' }}>
              <Zap size={12} style={{ color: 'var(--primary)' }} />
              <span style={{ fontSize: '12px', fontWeight: 800 }}>{profile.tokens}</span>
            </div>
          )}
        </div>

        <div style={{ display: 'flex', gap: '6px', marginBottom: '24px', overflowX: 'auto', paddingBottom: '4px' }}>
          {TABS.map(tab => {
            const Icon = tab.icon;
            const active = activeTab === tab.id;
            return (
              <button key={tab.id} onClick={() => setActiveTab(tab.id)}
                style={{
                  padding: '10px 14px', borderRadius: 'var(--radius-md)',
                  border: active ? '2px solid var(--primary)' : '2px solid var(--gray-border)',
                  background: active ? 'var(--primary-light)' : 'var(--white)', cursor: 'pointer',
                  display: 'flex', alignItems: 'center', gap: '6px', whiteSpace: 'nowrap',
                  fontSize: '12px', fontWeight: 700, color: active ? 'var(--primary)' : 'var(--text-sub)', transition: 'all 0.2s',
                }}>
                <Icon size={14} /> {tab.label}
              </button>
            );
          })}
        </div>

        <AnimatePresence mode="wait">
          {/* ===== DOWNLOADER TAB ===== */}
          {activeTab === 'downloader' && (
            <motion.div key="dl" initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -8 }} transition={{ duration: 0.2 }}>
              {!isPremium ? <PremiumGate navigate={navigate} /> : (
                <>
                  <div style={{ padding: '20px', background: 'var(--gray-bg)', borderRadius: 'var(--radius-xl)', marginBottom: '20px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '16px' }}>
                      <Sparkles size={16} style={{ color: 'var(--primary)' }} />
                      <span style={{ fontSize: '14px', fontWeight: 700 }}>Download Media</span>
                    </div>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '8px', marginBottom: '16px' }}>
                      {PLATFORMS.map(p => (
                        <button key={p.id} onClick={() => setDlPlatform(p.id)}
                          style={{
                            padding: '10px 8px', borderRadius: 'var(--radius-md)',
                            border: dlPlatform === p.id ? `2px solid ${p.color}` : '2px solid var(--gray-border)',
                            background: dlPlatform === p.id ? `${p.color}10` : 'var(--white)', cursor: 'pointer',
                            display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '4px', transition: 'all 0.2s',
                          }}>
                          <span style={{ fontSize: '20px' }}>{p.icon}</span>
                          <span style={{ fontSize: '10px', fontWeight: 700, color: dlPlatform === p.id ? p.color : 'var(--text-muted)' }}>{p.name}</span>
                        </button>
                      ))}
                    </div>
                    <div style={{ display: 'flex', gap: '8px' }}>
                      <div style={{ flex: 1, position: 'relative' }}>
                        <Link2 size={16} style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }} />
                        <input className="input-style" type="url" placeholder="Paste video/image URL here..."
                          value={dlUrl} onChange={e => setDlUrl(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleDownload()}
                          style={{ width: '100%', padding: '12px 12px 12px 36px', borderRadius: 'var(--radius-md)', border: '1px solid var(--gray-border)', background: 'var(--white)', color: 'var(--text-main)', fontSize: '13px', boxSizing: 'border-box' }} />
                      </div>
                      <button className="btn-primary" onClick={handleDownload} disabled={dlLoading || !dlUrl.trim()}
                        style={{ padding: '12px 20px', display: 'flex', alignItems: 'center', gap: '6px', fontSize: '13px', whiteSpace: 'nowrap', opacity: (!dlUrl.trim() || dlLoading) ? 0.5 : 1 }}>
                        {dlLoading ? <><Loader2 size={14} className="spinner-icon" /> Fetching...</> : <><Download size={14} /> Download</>}
                      </button>
                    </div>
                  </div>

                  {dlError && (
                    <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}
                      style={{ padding: '16px', background: '#fee2e2', borderRadius: 'var(--radius-md)', marginBottom: '16px', display: 'flex', alignItems: 'center', gap: '10px' }}>
                      <AlertCircle size={18} style={{ color: '#ef4444', flexShrink: 0 }} />
                      <span style={{ fontSize: '13px', color: '#991b1b', fontWeight: 600 }}>{dlError}</span>
                    </motion.div>
                  )}

                  {dlResult && (
                    <motion.div initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }}
                      style={{ padding: '20px', background: 'var(--white)', border: '2px solid var(--gray-border)', borderRadius: 'var(--radius-xl)' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '16px' }}>
