                      {(dlResult.video || dlResult.url) && (
                        <a href={dlResult.video || dlResult.url} target="_blank" rel="noopener noreferrer" className="btn-primary"
                          style={{ display: 'inline-flex', alignItems: 'center', gap: '8px', padding: '12px 24px', textDecoration: 'none', fontSize: '13px' }}>
                          <Download size={14} /> Download Video
                        </a>
                      )}
                      {dlResult.music && (
                        <a href={dlResult.music} target="_blank" rel="noopener noreferrer"
                          style={{ display: 'inline-flex', alignItems: 'center', gap: '8px', padding: '12px 24px', marginLeft: '8px', textDecoration: 'none', fontSize: '13px', color: 'var(--primary)', fontWeight: 700 }}>
                          🎵 Download Audio
                        </a>
                      )}
                    </motion.div>
                  )}

                  <div style={{ marginTop: '20px', padding: '16px', background: 'var(--gray-bg)', borderRadius: 'var(--radius-md)' }}>
                    <p style={{ fontSize: '12px', color: 'var(--text-muted)', lineHeight: 1.6 }}>
                      Supported: TikTok, Instagram, YouTube, X/Twitter. Rate limited to 10 per minute.
                    </p>
                  </div>
                </>
              )}
            </motion.div>
          )}

          {/* ===== CANVA GENERATOR TAB ===== */}
          {activeTab === 'canva' && (
            <motion.div key="canva" initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -8 }} transition={{ duration: 0.2 }}>
              {!isPremium ? <PremiumGate navigate={navigate} /> : (
                <>
                  <div style={{ padding: '24px', background: 'linear-gradient(135deg, #0ea5e910, #06b6d410)', border: '2px solid var(--gray-border)', borderRadius: 'var(--radius-xl)', marginBottom: '16px' }}>
