                      </div>
                      <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '12px', marginBottom: '6px' }}>
                        <span style={{ color: 'var(--text-muted)' }}>Account type</span>
                        <span style={{ fontWeight: 700, color: '#f59e0b' }}>Alight Motion Premium</span>
                      </div>
                      <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '12px' }}>
                        <span style={{ color: 'var(--text-muted)' }}>Rate limit</span>
                        <span style={{ fontWeight: 700 }}>3 per 5 minutes</span>
                      </div>
                    </div>

                    <button className="btn-primary btn-glow" onClick={() => handleGenerate('alight')} disabled={genLoading}
                      style={{ width: '100%', padding: '14px', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', fontSize: '14px', opacity: genLoading ? 0.6 : 1, background: '#f59e0b', border: 'none' }}>
                      {genLoading ? <><Loader2 size={16} className="spinner-icon" /> Generating...</> : <><Sparkles size={16} /> Generate Alight Motion Account</>}
                    </button>
                  </div>

                  {alightAccount && <AccountCard account={alightAccount} onCopy={copyText} />}

                  {genHistory.filter(h => h.platform === 'alight').length > 0 && (
                    <div style={{ marginTop: '20px' }}>
                      <div style={{ fontSize: '13px', fontWeight: 700, marginBottom: '10px', color: 'var(--text-sub)' }}>Recent Generations</div>
                      {genHistory.filter(h => h.platform === 'alight').slice(0, 5).map((h, i) => (
                        <div key={i} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px 14px', background: 'var(--gray-bg)', borderRadius: 'var(--radius-md)', marginBottom: '6px', fontSize: '12px' }}>
                          <code style={{ fontFamily: 'var(--font-mono)', fontWeight: 600 }}>{h.email}</code>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                            <span style={{ color: 'var(--text-muted)' }}>{h.time}</span>
                            <button onClick={() => copyText(h.email + ':' + h.password)} style={{ background: 'none', border: 'none', cursor: 'pointer', padding: '2px', color: 'var(--text-muted)', display: 'flex' }}><Copy size={12} /></button>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </>
              )}
            </motion.div>
          )}

          {/* ===== VIRTUAL NUMBERS TAB ===== */}
          {activeTab === 'numbers' && (
            <motion.div key="nums" initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -8 }} transition={{ duration: 0.2 }}>
              <div style={{ marginBottom: '20px' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                  <Globe size={16} style={{ color: 'var(--primary)' }} />
                  <span style={{ fontSize: '14px', fontWeight: 700 }}>Virtual Number Providers</span>
                </div>
                <p style={{ fontSize: '12px', color: 'var(--text-muted)', lineHeight: 1.5 }}>
                  Get temporary phone numbers for SMS verification. These are third-party services.
                </p>
              </div>

              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                {VIRTUAL_PROVIDERS.map((provider, i) => (
                  <motion.a key={provider.name} href={provider.url} target="_blank" rel="noopener noreferrer"
                    initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.08 }}
                    style={{
                      padding: '20px', borderRadius: 'var(--radius-xl)', border: '2px solid var(--gray-border)',
                      background: 'var(--white)', textDecoration: 'none', color: 'var(--text-main)',
                      display: 'flex', alignItems: 'center', gap: '16px', transition: 'all 0.2s', cursor: 'pointer',
                    }} className="hover-lift">
                    <div style={{ width: '48px', height: '48px', background: `${provider.color}15`, borderRadius: '14px', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                      <Phone size={22} style={{ color: provider.color }} />
                    </div>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontWeight: 800, fontSize: '15px', marginBottom: '4px' }}>{provider.name}</div>
                      <div style={{ fontSize: '12px', color: 'var(--text-sub)', lineHeight: 1.4 }}>{provider.desc}</div>
                    </div>
                    <ExternalLink size={16} style={{ color: 'var(--text-muted)', flexShrink: 0 }} />
                  </motion.a>
                ))}
              </div>

              <div style={{ marginTop: '24px', padding: '20px', background: 'var(--gray-bg)', borderRadius: 'var(--radius-xl)' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '10px' }}>
                  <AlertCircle size={14} style={{ color: 'var(--text-muted)' }} />
                  <span style={{ fontSize: '13px', fontWeight: 700 }}>Important Notes</span>
                </div>
                <ul style={{ fontSize: '12px', color: 'var(--text-sub)', lineHeight: 1.8, paddingLeft: '16px', margin: 0 }}>
                  <li>Virtual numbers are provided by third-party services</li>
                  <li>Numbers may be shared — don't use for sensitive accounts</li>
                  <li>Availability varies by country and service</li>
                  <li>Free numbers refresh periodically</li>
                </ul>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
}
